mapper.select:
SELECT p.id, p.seller_id, p.title, p.description, p.category, p.`condition`, p.original_price, p.price, p.trade_location, p.negotiable, p.images, p.status, p.created_at, p.updated_at, u.nickname AS seller_nickname, u.avatar AS seller_avatar, u.credit_score AS seller_credit_score FROM products p JOIN users u ON p.seller_id = u.id
AND p.status = #{status}
AND p.title LIKE CONCAT('%', #{keyword}, '%')
ORDER BY p.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM products p


        AND p.status = #{status}


        AND p.title LIKE CONCAT('%', #{keyword}, '%')
